# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs). Prevent directory traversal attacks.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _uploadsFolder = @"C:\uploads";

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            if (string.IsNullOrEmpty(filename))
                return BadRequest("Filename is required");

            var filePath = Path.Combine(_uploadsFolder, filename);

            if (!File.Exists(filePath))
                return NotFound($"File {filename} not found");

            var fileExtension = Path.GetExtension(filename).ToLower();

            switch (fileExtension)
            {
                case ".pdf":
                    return File(System.IO.File.ReadAllBytes(filePath), "application/pdf", filename);
                case ".docx":
                case ".doc":
                case ".xls":
                case ".xlsx":
                case ".ppt":
                case ".pptx":
                    return File(System.IO.File.ReadAllBytes(filePath), "application/vnd.openxmlformats-officedocument.wordprocessingml.document", filename);
                default:
                    var mimeType = GetMimeType(fileExtension);
                    if (string.IsNullOrEmpty(mimeType))
                        return NotFound($"Unsupported file type: {fileExtension}");
                    return File(System.IO.File.ReadAllBytes(filePath), mimeType, filename);
            }
        }

        private string GetMimeType(string extension)
        {
            switch (extension.ToLower())
            {
                case ".jpg":
                case ".jpeg":
                    return "image/jpeg";
                case ".png":
                    return "image/png";
                // Add more mime types as needed
                default:
                    return null;
            }
        }
    }
}